// Buscar cada tipo de cadastro da API ATAK em sequência
const configs = $('Buscar Configs de Cadastro').all();
const results = [];

// Mapear endpoint_nome → tipo_cadastro
const TIPO_MAP = {
  'WRCAD009_fornecedores': 'fornecedor',
  'WRCAD_motoristas': 'motorista',
  'WRCAD_funcionarios': 'funcionario',
  'WRCAD_veiculos': 'veiculo',
  'WRCAD_produtos': 'produto'
};

for (const cfg of configs) {
  const c = cfg.json;
  const tipoCadastro = TIPO_MAP[c.endpoint_nome] || 'fornecedor';

  results.push({
    json: {
      config_id: c.id,
      endpoint_nome: c.endpoint_nome,
      endpoint_url: c.endpoint_url,
      tipo_cadastro: tipoCadastro,
      parametros: c.parametros_json
    }
  });
}

return results;

// Transformar resposta da API em registros de staging
const items = $input.all();
const crypto = require('crypto');
const syncLogId = $('Criar Log de Sync').first().json.id;
const results = [];

for (const item of items) {
  const dados = Array.isArray(item.json) ? item.json : (item.json.data || [item.json]);
  // Recuperar tipo do cadastro do nó anterior
  // Como o HTTP Request pode perder o contexto, buscamos do item
  const tipoCadastro = item.json._tipo_cadastro || 
    $('Mapear Endpoints → Tipos').first().json.tipo_cadastro || 'fornecedor';

  for (const reg of dados) {
    // Hash para dedup
    const hashInput = [tipoCadastro, reg.codigo || reg.placa || reg.id || '', reg.nome || ''].join('|');
    const hash = crypto.createHash('sha256').update(hashInput).digest('hex');

    const staging = {
      sync_log_id: syncLogId,
      tipo_cadastro: tipoCadastro,
      atak_id: reg.id || reg.atak_id || null,
      codigo: reg.codigo || reg.placa || String(reg.id),
      nome: reg.nome || reg.descricao || reg.razao_social || '',
      apelido: reg.apelido || reg.nome_fantasia || null,
      ativo: reg.ativo !== false,
      hash_registro: hash,
      payload_json: reg
    };

    // Campos específicos por tipo
    if (tipoCadastro === 'fornecedor') {
      staging.cnpj = reg.cnpj || reg.cpf_cnpj || null;
      staging.uf = reg.uf || reg.estado || null;
    }
    if (tipoCadastro === 'motorista') {
      staging.cnh = reg.cnh || null;
      staging.categoria_cnh = reg.categoria_cnh || reg.categoria || null;
      staging.placa_padrao = reg.placa_padrao || reg.placa || null;
      staging.telefone = reg.telefone || reg.celular || null;
    }
    if (tipoCadastro === 'funcionario') {
      staging.cargo = reg.cargo || reg.funcao || null;
      staging.setor = reg.setor || reg.departamento || null;
      staging.telefone = reg.telefone || reg.celular || null;
      staging.email = reg.email || null;
      staging.data_admissao = reg.data_admissao || null;
    }
    if (tipoCadastro === 'veiculo') {
      staging.placa = reg.placa || reg.codigo || null;
      staging.tipo_veiculo = reg.tipo_veiculo || reg.tipo || 'OUTROS';
      staging.funcao_veiculo = reg.funcao || reg.funcao_veiculo || 'outros';
      staging.renavam = reg.renavam || null;
      staging.ano_fabricacao = parseInt(reg.ano_fabricacao || reg.ano) || null;
      staging.capacidade_kg = parseFloat(reg.capacidade_kg || reg.capacidade) || null;
      staging.uf = reg.uf || null;
    }
    if (tipoCadastro === 'produto') {
      staging.grupo = reg.grupo || reg.categoria || null;
      staging.unidade = reg.unidade || 'PÇ';
      staging.peso_medio_kg = parseFloat(reg.peso_medio_kg || reg.peso_medio) || null;
    }

    results.push({ json: staging });
  }
}

return results;

// Consolidar resultado e atualizar log
const resultado = $input.first().json;
const syncLogId = $('Criar Log de Sync').first().json.id;
const totalStaging = $('Transformar → Staging').all().length;

return [{
  json: {
    id: syncLogId,
    status: (resultado.erros || 0) > 0 ? 'parcial' : 'sucesso',
    total_registros: totalStaging,
    novos: resultado.inseridos || 0,
    atualizados: resultado.atualizados || 0,
    erros: resultado.erros || 0,
    fim: new Date().toISOString(),
    mensagem: `Cadastros: ${resultado.inseridos || 0} novos, ${resultado.atualizados || 0} atualizados, ${resultado.erros || 0} erros`,
    detalhes_json: {
      resultado,
      execution_id: $execution.id
    }
  }
}];

// Após sync de cadastros, re-resolver vínculos pendentes em cargas
// Busca cargas que têm códigos mas sem ID resolvido
return [{ json: { action: 'relink_pending' } }];

// Para cada carga com vínculo pendente, fazer UPDATE para re-disparar o trigger
const cargas = $input.all().filter(c => c.json.id);
if (cargas.length === 0) return [{ json: { relinked: 0 } }];

return cargas.map(c => ({
  json: {
    id: c.json.id,
    // UPDATE vazio para re-disparar fn_resolver_vinculos_carga
    atualizado_trigger: new Date().toISOString()
  }
}));
